	private static final class TermFingerprint implements Comparable<TermFingerprint> {
		private final String signature;
		private final String className;
		private final int bindingCount;
		private final int connectivityDegree;
		private final int sharedWithScopeCount;
		private final boolean legacyPriority;

		private TermFingerprint(String signature, String className, int bindingCount, int connectivityDegree,
				int sharedWithScopeCount, boolean legacyPriority) {
			this.signature = signature;
			this.className = className;
			this.bindingCount = bindingCount;
			this.connectivityDegree = connectivityDegree;
			this.sharedWithScopeCount = sharedWithScopeCount;
			this.legacyPriority = legacyPriority;
		}

		@Override
		public int compareTo(TermFingerprint other) {
			int comparison = signature.compareTo(other.signature);
			if (comparison != 0) {
				return comparison;
			}
			comparison = className.compareTo(other.className);
			if (comparison != 0) {
				return comparison;
			}
			comparison = Integer.compare(bindingCount, other.bindingCount);
			if (comparison != 0) {
				return comparison;
			}
			comparison = Integer.compare(connectivityDegree, other.connectivityDegree);
			if (comparison != 0) {
				return comparison;
			}
			comparison = Integer.compare(sharedWithScopeCount, other.sharedWithScopeCount);
			if (comparison != 0) {
				return comparison;
			}
			return Boolean.compare(legacyPriority, other.legacyPriority);
		}

		@Override
		public boolean equals(Object other) {
			if (!(other instanceof TermFingerprint)) {
				return false;
			}
			TermFingerprint that = (TermFingerprint) other;
			return bindingCount == that.bindingCount
					&& connectivityDegree == that.connectivityDegree
					&& sharedWithScopeCount == that.sharedWithScopeCount
					&& legacyPriority == that.legacyPriority
					&& Objects.equals(signature, that.signature)
					&& Objects.equals(className, that.className);
		}

		@Override
		public int hashCode() {
			return Objects.hash(signature, className, bindingCount, connectivityDegree, sharedWithScopeCount,
					legacyPriority);
		}
	}

	private static final class PlannerTelemetrySnapshot {
		private final long joinEstimateCalls;
		private final long joinEstimateCacheHits;
		private final long orderingJoinEstimateCalls;
		private final long rerankingJoinEstimateCalls;
		private final long bushyJoinEstimateCalls;
		private final long memoizationGuardChecks;
		private final long memoizationGuardSkips;
		private final double memoizationGuardDecisionHitRate;
		private final long runtimeSamplingCandidateSourceBaselineOnly;
		private final long runtimeSamplingCandidateSourceTopKEnumerated;
		private final long runtimeSamplingCandidateSourcePromotedPair;
		private final long runtimeSamplingCandidateSourceGuardSkipped;
		private final long componentOrderingReuseHits;
		private final long componentOrderingReuseMisses;
		private final long runtimeSamplingNanos;

		private PlannerTelemetrySnapshot(long joinEstimateCalls, long joinEstimateCacheHits,
				long orderingJoinEstimateCalls, long rerankingJoinEstimateCalls, long bushyJoinEstimateCalls,
				long memoizationGuardChecks, long memoizationGuardSkips, double memoizationGuardDecisionHitRate,
				long runtimeSamplingCandidateSourceBaselineOnly, long runtimeSamplingCandidateSourceTopKEnumerated,
				long runtimeSamplingCandidateSourcePromotedPair, long runtimeSamplingCandidateSourceGuardSkipped,
				long componentOrderingReuseHits, long componentOrderingReuseMisses, long runtimeSamplingNanos) {
			this.joinEstimateCalls = joinEstimateCalls;
			this.joinEstimateCacheHits = joinEstimateCacheHits;
			this.orderingJoinEstimateCalls = orderingJoinEstimateCalls;
			this.rerankingJoinEstimateCalls = rerankingJoinEstimateCalls;
			this.bushyJoinEstimateCalls = bushyJoinEstimateCalls;
			this.memoizationGuardChecks = memoizationGuardChecks;
			this.memoizationGuardSkips = memoizationGuardSkips;
			this.memoizationGuardDecisionHitRate = memoizationGuardDecisionHitRate;
			this.runtimeSamplingCandidateSourceBaselineOnly = runtimeSamplingCandidateSourceBaselineOnly;
			this.runtimeSamplingCandidateSourceTopKEnumerated = runtimeSamplingCandidateSourceTopKEnumerated;
			this.runtimeSamplingCandidateSourcePromotedPair = runtimeSamplingCandidateSourcePromotedPair;
			this.runtimeSamplingCandidateSourceGuardSkipped = runtimeSamplingCandidateSourceGuardSkipped;
			this.componentOrderingReuseHits = componentOrderingReuseHits;
			this.componentOrderingReuseMisses = componentOrderingReuseMisses;
			this.runtimeSamplingNanos = runtimeSamplingNanos;
		}

		private double memoizationHitRate() {
			if (joinEstimateCalls <= 0L) {
				return 0.0;
			}
			return (double) joinEstimateCacheHits / (double) joinEstimateCalls;
		}
	}

