	private static boolean readBooleanProperty(String key, boolean defaultValue) {
		String value = System.getProperty(key);
		if (value == null || value.isBlank()) {
			return defaultValue;
		}
		return Boolean.parseBoolean(value.trim());
	}

	private static long readNonNegativeLongProperty(String key, long defaultValue) {
		String value = System.getProperty(key);
		if (value == null || value.isBlank()) {
			return defaultValue;
		}

		try {
			long parsed = Long.parseLong(value.trim());
			return parsed >= 0 ? parsed : defaultValue;
		} catch (NumberFormatException ignored) {
			return defaultValue;
		}
	}

	private static double readNonNegativeDoubleProperty(String key, double defaultValue) {
		String value = System.getProperty(key);
		if (value == null || value.isBlank()) {
			return defaultValue;
		}

		try {
			double parsed = Double.parseDouble(value.trim());
			return parsed >= 0.0 ? parsed : defaultValue;
		} catch (NumberFormatException ignored) {
			return defaultValue;
		}
	}

	private static double readBoundedDoubleProperty(String key, double defaultValue, double min, double max) {
		String value = System.getProperty(key);
		if (value == null || value.isBlank()) {
			return defaultValue;
		}

		try {
			double parsed = Double.parseDouble(value.trim());
			return Math.min(max, Math.max(min, parsed));
		} catch (NumberFormatException ignored) {
			return defaultValue;
		}
	}

	private static int readPositiveIntProperty(String key, int defaultValue) {
		String value = System.getProperty(key);
		if (value == null || value.isBlank()) {
			return defaultValue;
		}

		try {
			int parsed = Integer.parseInt(value.trim());
			return parsed > 0 ? parsed : defaultValue;
		} catch (NumberFormatException ignored) {
			return defaultValue;
		}
	}

	private static int readNonNegativeIntProperty(String key, int defaultValue) {
		String value = System.getProperty(key);
		if (value == null || value.isBlank()) {
			return defaultValue;
		}

		try {
			int parsed = Integer.parseInt(value.trim());
			return parsed >= 0 ? parsed : defaultValue;
		} catch (NumberFormatException ignored) {
			return defaultValue;
		}
	}

	private static long readPositiveLongProperty(String key, long defaultValue) {
		String value = System.getProperty(key);
		if (value == null || value.isBlank()) {
			return defaultValue;
		}

		try {
			long parsed = Long.parseLong(value.trim());
			return parsed > 0 ? parsed : defaultValue;
		} catch (NumberFormatException ignored) {
			return defaultValue;
		}
	}

